import { useNavigation } from '@react-navigation/native';
import { NativeStackNavigationProp } from '@react-navigation/native-stack';
import React from 'react';
import { Pressable, StyleSheet, Text, View } from 'react-native';
import { RootStackParamList } from '../navigation/AppNavigator';

type CustomerBottomNavProps = {
  active: 'CustomerHome' | 'CustomerOrders' | 'CustomerSubscription' | 'CustomerWallet' | 'Profile';
};

const items = [
  { key: 'CustomerHome', label: 'Home', short: 'H' },
  { key: 'CustomerOrders', label: 'Orders', short: 'O' },
  { key: 'CustomerSubscription', label: 'Plan', short: 'P' },
  { key: 'CustomerWallet', label: 'Wallet', short: 'W' }
] as const;

const CustomerBottomNav = ({ active }: CustomerBottomNavProps) => {
  const navigation = useNavigation<NativeStackNavigationProp<RootStackParamList>>();

  return (
    <View style={styles.container}>
      {items.map((item) => {
        const selected = item.key === active;
        return (
          <Pressable key={item.key} style={styles.item} onPress={() => navigation.navigate(item.key)}>
            <View style={[styles.iconWrap, selected && styles.iconWrapSelected]}>
              <Text style={[styles.iconText, selected && styles.iconTextSelected]}>{item.short}</Text>
            </View>
            <Text style={[styles.label, selected && styles.labelSelected]}>{item.label}</Text>
          </Pressable>
        );
      })}
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    position: 'absolute',
    left: 16,
    right: 16,
    bottom: 8,
    backgroundColor: 'white',
    borderRadius: 22,
    flexDirection: 'row',
    justifyContent: 'space-between',
    paddingVertical: 10,
    paddingHorizontal: 12,
    shadowColor: '#10324A',
    shadowOpacity: 0.12,
    shadowRadius: 16,
    elevation: 8
  },
  item: {
    flex: 1,
    alignItems: 'center'
  },
  iconWrap: {
    width: 32,
    height: 32,
    borderRadius: 16,
    backgroundColor: '#EAF7FF',
    alignItems: 'center',
    justifyContent: 'center'
  },
  iconWrapSelected: {
    backgroundColor: '#0D8DD8'
  },
  iconText: {
    color: '#0D63A8',
    fontSize: 13,
    fontWeight: '800'
  },
  iconTextSelected: {
    color: 'white'
  },
  label: {
    marginTop: 6,
    color: '#6D8699',
    fontSize: 11,
    fontWeight: '700'
  },
  labelSelected: {
    color: '#0D63A8'
  }
});

export default CustomerBottomNav;
